export function createDeterministicAdminDashboardShellAdapter(): AdminDashboardShellAdapter {
  return {
    async load(_role, signal) {
      if (signal.aborted) throw new DOMException("The operation was aborted.", "AbortError");
      return {
        activities: [
          {
            actor: "Asha Rao",
            id: "activity-review",
            occurredAt: FIXTURE_TIMES.activityReview,
            status: "complete",
            summary: "Reviewed the component evidence bundle",
          },
          {
            actor: "Mina Park",
            id: "activity-export",
            occurredAt: FIXTURE_TIMES.activityExport,
            status: "in-progress",
            summary: "Prepared the static documentation export",
          },
          {
            actor: "Jon Bell",
            id: "activity-follow-up",
            occurredAt: FIXTURE_TIMES.activityFollowUp,
            status: "attention",
            summary: "Requested a keyboard evidence follow-up",
          },
        ],
        breadcrumbs: [
          { href: "#overview", id: "workspace", label: "Workspace" },
          { id: "operations", label: "Operations" },
        ],
        navigation: [
          {
            id: "monitoring",
            items: [
              {
                href: "#overview",
                id: "overview",
                label: "Overview",
                roles: ["analyst", "editor", "owner", "viewer"],
              },
              {
                href: "#activity",
                id: "activity",
                label: "Activity",
                roles: ["analyst", "editor", "owner"],
              },
            ],
            label: "Monitoring",
          },
          {
            id: "management",
            items: [
              {
                href: "#members",
                id: "members",
                label: "Members",
                roles: ["owner"],
              },
              {
                href: "#settings",
                id: "settings",
                label: "Settings",
                roles: ["editor", "owner"],
              },
            ],
            label: "Management",
          },
        ],
        notifications: [
          {
            createdAt: FIXTURE_TIMES.notificationEvidence,
            id: "notification-evidence",
            message: "The keyboard evidence record is ready for review.",
            read: false,
            title: "Evidence ready",
          },
          {
            createdAt: FIXTURE_TIMES.notificationExport,
            id: "notification-export",
            message: "The last static export completed without drift.",
            read: true,
            title: "Export complete",
          },
        ],
        title: "Operations overview",
        trend: [
          { id: "mon", label: "Monday", value: 18 },
          { id: "tue", label: "Tuesday", value: 24 },
          { id: "wed", label: "Wednesday", value: 21 },
          { id: "thu", label: "Thursday", value: 31 },
          { id: "fri", label: "Friday", value: 28 },
        ],
        updatedAt: FIXTURE_TIMES.updated,
      };
    },
    async markNotificationRead(_notificationId, signal) {
      if (signal.aborted) throw new DOMException("The operation was aborted.", "AbortError");
    },
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

import type {
  AdminDashboardRole,
  AdminDashboardShellAdapter,
  AdminDashboardSnapshot,
} from "./admin-dashboard-shell-adapter";

export type AdminDashboardShellLoadState = "empty" | "error" | "loading" | "offline" | "ready";

export interface UseAdminDashboardShellOptions {
  /** Consumer adapter that owns dashboard loading and optional notification mutation. */
  readonly adapter: AdminDashboardShellAdapter;
  /** Prevents adapter requests and exposes an explicit offline recovery state. */
  readonly offline?: boolean;
  /** Role supplied to loading and optional permission-aware navigation filtering. */
  readonly role?: AdminDashboardRole;
}

export function useAdminDashboardShell({
  adapter,
  offline = false,
  role = "owner",
}: UseAdminDashboardShellOptions) {
  const [snapshot, setSnapshot] = useState<AdminDashboardSnapshot | null>(null);
  const [state, setState] = useState<AdminDashboardShellLoadState>(offline ? "offline" : "loading");
  const [error, setError] = useState("");
  const activeRequest = useRef<AbortController | null>(null);

  const reload = useCallback(async () => {
    activeRequest.current?.abort();
    if (offline) {
      setState("offline");
      return;
    }
    const controller = new AbortController();
    activeRequest.current = controller;
    setState("loading");
    setError("");
    try {
      const next = await adapter.load(role, controller.signal);
      if (controller.signal.aborted) return;
      setSnapshot(next);
      setState(next.activities.length === 0 && next.trend.length === 0 ? "empty" : "ready");
    } catch (loadError) {
      if (controller.signal.aborted) return;
      setError(loadError instanceof Error ? loadError.message : "The dashboard could not load.");
      setState("error");
    } finally {
      if (activeRequest.current === controller) activeRequest.current = null;
    }
  }, [adapter, offline, role]);

  useEffect(() => {
    void reload();
    return () => activeRequest.current?.abort();
  }, [reload]);

  const markNotificationRead = async (notificationId: string) => {
    if (adapter.markNotificationRead === undefined || offline) return;
    const controller = new AbortController();
    activeRequest.current?.abort();
    activeRequest.current = controller;
    const previous = snapshot;
    setSnapshot((current) =>
      current === null
        ? current
        : {
            ...current,
            notifications: current.notifications.map((notification) =>
              notification.id === notificationId ? { ...notification, read: true } : notification,
            ),
          },
    );
    try {
      await adapter.markNotificationRead(notificationId, controller.signal);
      setError("");
    } catch (markError) {
      if (controller.signal.aborted) return;
      setSnapshot(previous);
      setError(
        markError instanceof Error ? markError.message : "The notification could not be updated.",
      );
      setState("error");
    } finally {
      if (activeRequest.current === controller) activeRequest.current = null;
    }
  };

  return { error, markNotificationRead, reload, snapshot, state } as const;
}

@layer mergora.components {
  .mrg-admin-dashboard-shell {
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-layout"] {
    display: grid;
    grid-template-columns: minmax(13rem, 18rem) minmax(0, 1fr);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-block-start: 0;
    border-radius: 0 0 var(--mrg-semantic-radius-panel) var(--mrg-semantic-radius-panel);
    overflow: clip;
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-main"] {
    display: grid;
    align-content: start;
    gap: var(--mrg-semantic-space-stack-lg);
    min-inline-size: 0;
    padding: var(--mrg-semantic-density-panel-padding);
    border-inline-start: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-strong);
    background: var(--mrg-semantic-color-background-canvas);
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-heading"] {
    display: flex;
    flex-wrap: wrap;
    align-items: end;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-stack-md);
    padding-block-end: var(--mrg-semantic-space-inset-md);
    border-block-end: var(--mrg-semantic-border-width-emphasis) solid
      var(--mrg-semantic-color-brand-action);
  }

  .mrg-admin-dashboard-shell h1,
  .mrg-admin-dashboard-shell h2 {
    margin: 0;
    font-weight: var(--mrg-semantic-font-weight-heading);
    line-height: var(--mrg-semantic-font-line-height-heading);
    text-wrap: balance;
  }

  .mrg-admin-dashboard-shell h1 {
    font-size: var(--mrg-semantic-font-size-heading-medium);
  }

  .mrg-admin-dashboard-shell h2 {
    font-size: var(--mrg-semantic-font-size-heading-small);
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-heading"] p,
  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] p {
    margin-block: var(--mrg-semantic-space-stack-xs) 0;
    color: var(--mrg-semantic-color-foreground-muted);
    line-height: var(--mrg-semantic-font-line-height-body);
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-role-context"] {
    max-inline-size: var(--mrg-semantic-size-content-prose);
    padding: var(--mrg-semantic-space-inset-sm);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-accent-border);
    border-radius: var(--mrg-semantic-radius-compact);
    color: var(--mrg-semantic-color-accent-foreground-on-subtle);
    background: var(--mrg-semantic-color-accent-background-subtle);
  }

  .mrg-admin-dashboard-shell
    :is([data-slot="admin-dashboard-trend"], [data-slot="admin-dashboard-activity"]) {
    display: grid;
    gap: var(--mrg-semantic-space-stack-sm);
    min-inline-size: 0;
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] {
    display: grid;
    gap: var(--mrg-semantic-space-stack-sm);
    padding: var(--mrg-semantic-space-inset-md);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-surface);
    background: var(--mrg-semantic-color-background-surface);
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] > div {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-inline-sm);
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] ul {
    display: grid;
    gap: 0;
    padding: 0;
    margin: 0;
    border-block-start: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    list-style: none;
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] li {
    display: flex;
    align-items: start;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-inline-md);
    padding-block: var(--mrg-semantic-space-inset-sm);
    border-block-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] li:not([data-read]) {
    color: var(--mrg-semantic-color-selection-foreground);
    background: var(--mrg-semantic-color-selection-background);
  }

  .mrg-admin-dashboard-shell [data-slot="admin-dashboard-loading"] {
    display: grid;
    gap: var(--mrg-semantic-space-stack-md);
    padding: var(--mrg-semantic-space-section);
  }

  .mrg-admin-dashboard-shell :focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }

  @media (max-width: 48rem) {
    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-layout"] {
      grid-template-columns: minmax(0, 1fr);
    }

    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-main"] {
      padding: var(--mrg-semantic-space-inset-md);
      border-inline-start: 0;
      border-block-start: var(--mrg-semantic-border-width-default) solid
        var(--mrg-semantic-color-border-strong);
    }

    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] li {
      align-items: stretch;
      flex-direction: column;
    }
  }

  @media (pointer: coarse) {
    .mrg-admin-dashboard-shell button,
    .mrg-admin-dashboard-shell a {
      min-block-size: var(--mrg-semantic-size-target-preferred);
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .mrg-admin-dashboard-shell * {
      scroll-behavior: auto;
      transition-duration: var(--mrg-semantic-motion-duration-reduced);
    }
  }

  @media (forced-colors: active) {
    .mrg-admin-dashboard-shell,
    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-layout"],
    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-main"],
    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-heading"],
    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-role-context"],
    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"],
    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] li {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
    }

    .mrg-admin-dashboard-shell [data-slot="admin-dashboard-notifications"] li:not([data-read]) {
      border-color: Highlight;
      color: CanvasText;
      background: Canvas;
      outline: var(--mrg-semantic-border-width-emphasis) solid Highlight;
      outline-offset: calc(-1 * var(--mrg-semantic-border-width-emphasis));
    }

    .mrg-admin-dashboard-shell :focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

"use client";

import "./admin-dashboard-shell.css";

import { useId, useMemo, useState, type HTMLAttributes } from "react";

import { Alert } from "../../components/alert/alert";
import { Badge } from "../../components/badge/badge";
import { Breadcrumb } from "../../components/breadcrumb/breadcrumb";
import { Button } from "../../components/button/button";
import { Chart } from "../../components/chart/chart";
import { DataTable, type DataTableColumn } from "../../components/data-table/data-table";
import { EmptyState } from "../../components/empty-state/empty-state";
import { Navbar } from "../../components/navbar/navbar";
import { Sidebar, type SidebarGroup } from "../../components/sidebar/sidebar";
import { Skeleton } from "../../components/skeleton/skeleton";
import type {
  AdminDashboardActivity,
  AdminDashboardRole,
  AdminDashboardShellAdapter,
} from "./admin-dashboard-shell-adapter";
import { useAdminDashboardShell } from "./admin-dashboard-shell-state";

export interface AdminDashboardShellProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "children" | "onChange"
> {
  /** Consumer adapter that owns dashboard data, authorization, and notification persistence. */
  readonly adapter: AdminDashboardShellAdapter;
  /** Controlled current navigation section identifier; use with `onSectionChange`. */
  readonly currentSectionId?: string;
  /** Initial navigation section identifier for uncontrolled use. */
  readonly defaultSectionId?: string;
  /** Enables chart interaction; false keeps the chart as a static readable summary. */
  readonly interactiveChart?: boolean;
  /** Prevents adapter requests and presents explicit offline recovery context. */
  readonly offline?: boolean;
  /** Reports controlled or uncontrolled dashboard section changes. */
  readonly onSectionChange?: (sectionId: string) => void;
  /** Filters navigation by the supplied role; false shows the adapter's complete navigation. */
  readonly permissionFilteredNavigation?: boolean;
  /** Current dashboard role used for loading and optional navigation filtering. */
  readonly role?: AdminDashboardRole;
  /** Adds activity filtering and sorting controls; false removes query UI while retaining the table. */
  readonly showActivityQueryTools?: boolean;
  /** Adds a tabular trend alternative; false removes the duplicate table semantics. */
  readonly showChartDataTable?: boolean;
  /** Adds notification review and optional read actions; false removes that entire surface. */
  readonly showNotifications?: boolean;
  /** Adds visible role context near the dashboard heading; false removes that explanatory output. */
  readonly showRoleContext?: boolean;
}

const activityColumns: readonly DataTableColumn<AdminDashboardActivity>[] = [
  {
    cell: (row) => row.summary,
    filterValue: (row) => `${row.summary} ${row.actor} ${row.status}`,
    header: "Activity",
    id: "summary",
    sortable: true,
    sortValue: (row) => row.summary,
  },
  {
    cell: (row) => row.actor,
    filterValue: (row) => row.actor,
    header: "Owner",
    id: "actor",
    sortable: true,
    sortValue: (row) => row.actor,
  },
  {
    cell: (row) => (
      <Badge
        kind="status"
        variant={
          row.status === "complete" ? "success" : row.status === "attention" ? "warning" : "info"
        }
      >
        {row.status === "in-progress" ? "In progress" : row.status}
      </Badge>
    ),
    header: "Status",
    id: "status",
    sortable: true,
    sortValue: (row) => row.status,
  },
  {
    cell: (row) =>
      new Intl.DateTimeFormat(undefined, { dateStyle: "medium", timeStyle: "short" }).format(
        new Date(row.occurredAt),
      ),
    header: "Updated",
    id: "updated",
    sortable: true,
    sortValue: (row) => row.occurredAt,
  },
];

export function AdminDashboardShell({
  adapter,
  className,
  currentSectionId,
  defaultSectionId = "overview",
  interactiveChart = false,
  offline = false,
  onSectionChange,
  permissionFilteredNavigation = false,
  role = "owner",
  showActivityQueryTools = false,
  showChartDataTable = false,
  showNotifications = false,
  showRoleContext = false,
  ...props
}: AdminDashboardShellProps) {
  const dashboard = useAdminDashboardShell({ adapter, offline, role });
  const [uncontrolledSection, setUncontrolledSection] = useState(defaultSectionId);
  const selectedSection = currentSectionId ?? uncontrolledSection;
  const mainId = `mrg-admin-dashboard-main-${useId().replaceAll(":", "")}`;
  const snapshot = dashboard.snapshot;
  const navigation = useMemo<readonly SidebarGroup[]>(() => {
    if (snapshot === null) return [];
    return snapshot.navigation
      .map((group) => ({
        ...group,
        items: group.items
          .filter((item) => !permissionFilteredNavigation || item.roles.includes(role))
          .map(({ roles: _roles, ...item }) => item),
      }))
      .filter((group) => group.items.length > 0);
  }, [permissionFilteredNavigation, role, snapshot]);

  const chooseSection = (sectionId: string) => {
    if (currentSectionId === undefined) setUncontrolledSection(sectionId);
    onSectionChange?.(sectionId);
  };

  return (
    <div
      {...props}
      className={
        className === undefined
          ? "mrg-admin-dashboard-shell"
          : `mrg-admin-dashboard-shell ${className}`
      }
      data-slot="admin-dashboard-shell"
    >
      <Navbar
        brand={<strong>Mergora workspace</strong>}
        currentId="dashboard"
        items={[
          { href: "#dashboard", id: "dashboard", label: "Dashboard" },
          { href: "#evidence", id: "evidence", label: "Evidence" },
          { href: "#settings", id: "settings", label: "Settings" },
        ]}
        label="Workspace navigation"
        onNavigate={(event, item) => {
          event.preventDefault();
          chooseSection(item.id);
        }}
        skipLink={{ href: `#${mainId}`, label: "Skip to dashboard content" }}
      />
      {dashboard.state === "loading" ? (
        <div
          aria-busy="true"
          aria-label="Loading dashboard"
          data-slot="admin-dashboard-loading"
          role="status"
        >
          <Skeleton blockSize={40} />
          <Skeleton blockSize={160} />
          <span>Loading dashboard...</span>
        </div>
      ) : null}
      {dashboard.state === "error" ? (
        <Alert
          actions={<Button onClick={() => void dashboard.reload()}>Retry dashboard</Button>}
          description={dashboard.error || "The dashboard could not continue."}
          title="Dashboard unavailable"
          variant="error"
        />
      ) : null}
      {dashboard.state === "offline" ? (
        <Alert
          description="Reconnect to refresh activity and notification state. Previously supplied content remains consumer-owned."
          title="Dashboard is offline"
          variant="warning"
        />
      ) : null}
      {snapshot === null ? null : (
        <div data-slot="admin-dashboard-layout">
          <Sidebar
            {...(navigation.some((group) => group.items.some((item) => item.id === selectedSection))
              ? { currentId: selectedSection }
              : {})}
            groups={navigation}
            label="Dashboard sections"
            onNavigate={(event, item) => {
              event.preventDefault();
              chooseSection(item.id);
            }}
          />
          <main data-slot="admin-dashboard-main" id={mainId} tabIndex={-1}>
            <Breadcrumb
              collapse
              items={snapshot.breadcrumbs.map((item, index) => ({
                ...item,
                current: index === snapshot.breadcrumbs.length - 1,
              }))}
            />
            <header data-slot="admin-dashboard-heading">
              <div>
                <h1>{snapshot.title}</h1>
                <p>
                  Updated{" "}
                  {new Intl.DateTimeFormat(undefined, {
                    dateStyle: "long",
                    timeStyle: "short",
                  }).format(new Date(snapshot.updatedAt))}
                </p>
              </div>
              {showRoleContext ? (
                <p data-slot="admin-dashboard-role-context">
                  Navigation preview for the <strong>{role}</strong> role. Backend authorization
                  remains consumer-owned.
                </p>
              ) : null}
            </header>
            {dashboard.state === "empty" ? (
              <EmptyState
                context="first-use"
                description="The adapter returned no trend or activity records."
                primaryAction={
                  <Button onClick={() => void dashboard.reload()}>Refresh dashboard</Button>
                }
                title="No dashboard evidence yet"
              />
            ) : (
              <>
                <section aria-labelledby={`${mainId}-trend`} data-slot="admin-dashboard-trend">
                  <h2 id={`${mainId}-trend`}>Review activity</h2>
                  <Chart
                    dataTableFallback={showChartDataTable ? "visible" : "disclosure"}
                    description="Completed evidence reviews during the current working week."
                    interactive={interactiveChart}
                    name="Weekly evidence reviews"
                    points={snapshot.trend}
                    valueLabel="Reviews"
                  />
                </section>
                <section
                  aria-labelledby={`${mainId}-activity`}
                  data-slot="admin-dashboard-activity"
                >
                  <h2 id={`${mainId}-activity`}>Recent activity</h2>
                  <DataTable
                    caption="Recent workspace activity"
                    columns={activityColumns}
                    getRowId={(row) => row.id}
                    paginated={showActivityQueryTools}
                    rows={snapshot.activities}
                    searchable={showActivityQueryTools}
                    showQuerySummary={showActivityQueryTools}
                  />
                </section>
              </>
            )}
            {showNotifications ? (
              <aside
                aria-labelledby={`${mainId}-notifications`}
                data-slot="admin-dashboard-notifications"
              >
                <div>
                  <h2 id={`${mainId}-notifications`}>Notifications</h2>
                  <Badge
                    count={snapshot.notifications.filter((item) => !item.read).length}
                    kind="count"
                    label="Unread notifications"
                  />
                </div>
                {snapshot.notifications.length === 0 ? (
                  <p>No notifications.</p>
                ) : (
                  <ul>
                    {snapshot.notifications.map((notification) => (
                      <li data-read={notification.read || undefined} key={notification.id}>
                        <div>
                          <strong>{notification.title}</strong>
                          <p>{notification.message}</p>
                        </div>
                        {notification.read || adapter.markNotificationRead === undefined ? null : (
                          <Button
                            onClick={() => void dashboard.markNotificationRead(notification.id)}
                            size="small"
                            variant="quiet"
                          >
                            Mark read
                          </Button>
                        )}
                      </li>
                    ))}
                  </ul>
                )}
              </aside>
            ) : null}
          </main>
        </div>
      )}
    </div>
  );
}

